async function main() {
  let updated = 0;
  let errors = [];
  
  for (const u of updates) {
    try {
      const result = await prisma.product.update({
        where: { slug: u.slug },
        data: {
          description: u.description,
          metaDescription: u.metaDescription,
        },
      });
      const descWords = u.description.split(/\s+/).length;
      const metaLen = u.metaDescription.length;
      console.log(`✅ ${u.slug} | desc: ${descWords} words | meta: ${metaLen} chars`);
      updated++;
    } catch (err) {
      errors.push({ slug: u.slug, error: err.message });
      console.log(`❌ ${u.slug} | ${err.message}`);
    }
  }
  
  console.log(`\n${'='.repeat(60)}`);
  console.log(`Total: ${updates.length} | Updated: ${updated} | Errors: ${errors.length}`);
  if (errors.length) {
    console.log('\nErrors:');
    errors.forEach(e => console.log(`  - ${e.slug}: ${e.error}`));
  }
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
